import { describe, expect, it } from 'vitest';
import {
  initAttestationChain,
  attestHop,
  type AttestationSigner,
  type AttestationVerifier,
  type ChainBuildContext,
  type PrismAttestationChain,
} from './prism-attestation';
import {
  issueSlownessCertificate,
  verifySlownessCertificate,
  canonicalCertificateBytes,
  chainElapsedMs,
} from './slowness-certificate';
import type { PrismPath } from './temporal-prism';

// ─── Mock Crypto (same pattern as prism-attestation.test.ts) ────────

function mockSigner(did: string): AttestationSigner {
  return {
    did,
    async sign(message: Uint8Array): Promise<Uint8Array> {
      const sigText = `sig(${did})|${Array.from(message).join(',')}`;
      return new TextEncoder().encode(sigText);
    },
  };
}

const mockVerifier: AttestationVerifier = {
  async verify(did: string, message: Uint8Array, signature: Uint8Array): Promise<boolean> {
    const expected = `sig(${did})|${Array.from(message).join(',')}`;
    const expectedBytes = new TextEncoder().encode(expected);
    if (signature.length !== expectedBytes.length) return false;
    for (let i = 0; i < signature.length; i++) {
      if (signature[i] !== expectedBytes[i]) return false;
    }
    return true;
  },
};

function mockHashFn(data: Uint8Array | string): string {
  const bytes = typeof data === 'string' ? new TextEncoder().encode(data) : data;
  let h = 0;
  for (let i = 0; i < bytes.length; i++) {
    h = (h * 31 + bytes[i]) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

const ctx: ChainBuildContext = {
  hashFn: mockHashFn,
  verifier: mockVerifier,
};

// ─── Fixtures ───────────────────────────────────────────────────────

const mockPath: PrismPath = {
  source: 'GnosisTemporalPrism',
  originPidId: 'pid:earth',
  targetPidId: 'pid:sun',
  startEpochMs: 1_000_000,
  deliverAtEpochMs: 1_000_600,
  hops: [
    {
      fromPidId: 'pid:earth', toPidId: 'pid:mars',
      fromLabel: 'Earth', toLabel: 'Mars',
      propagationDelayMs: 300,
      departureEpochMs: 1_000_000, arrivalEpochMs: 1_000_300,
      arrivalPhase: 'rising', phaseScore: 0.9,
    },
    {
      fromPidId: 'pid:mars', toPidId: 'pid:sun',
      fromLabel: 'Mars', toLabel: 'Sun',
      propagationDelayMs: 300,
      departureEpochMs: 1_000_300, arrivalEpochMs: 1_000_600,
      arrivalPhase: 'peak', phaseScore: 0.5,
    },
  ],
  totalDelayMs: 600,
  actualArrivalEpochMs: 1_000_600,
  deliveryErrorMs: 0,
  averagePhaseScore: 0.7,
  onTime: true,
};

/** Build a valid chain that elapses exactly `elapsedMs` between hops. */
async function buildChainWithElapsed(elapsedMs: number): Promise<PrismAttestationChain> {
  let chain = initAttestationChain({
    chainId: 'c-slow-1',
    originDid: 'did:key:earth',
    targetDid: 'did:key:sun',
    path: mockPath,
    initialPayloadHash: 'h0',
    createdAtPLo: 1000,
  });
  chain = await attestHop({
    chain,
    signer: mockSigner('did:key:mars'),
    pidId: 'pid:mars',
    attestedAtPLo: 1000,
    attestedPhase: 'rising',
    incomingPayloadHash: 'h0',
    context: ctx,
  });
  chain = await attestHop({
    chain,
    signer: mockSigner('did:key:sun'),
    pidId: 'pid:sun',
    attestedAtPLo: 1000 + elapsedMs,
    attestedPhase: 'peak',
    incomingPayloadHash: 'h0',
    context: ctx,
  });
  return chain;
}

// ─── chainElapsedMs ─────────────────────────────────────────────────

describe('chainElapsedMs', () => {
  it('returns 0 for chains with fewer than 2 hops', async () => {
    const empty = initAttestationChain({
      chainId: 'c', originDid: 'd1', targetDid: 'd2',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 0,
    });
    expect(chainElapsedMs(empty)).toBe(0);
  });

  it('returns the difference between first and last hop timestamps', async () => {
    const chain = await buildChainWithElapsed(500);
    expect(chainElapsedMs(chain)).toBe(500);
  });
});

// ─── canonicalCertificateBytes ──────────────────────────────────────

describe('canonicalCertificateBytes', () => {
  it('is deterministic', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });
    const a = canonicalCertificateBytes(cert);
    const b = canonicalCertificateBytes(cert);
    expect(Array.from(a)).toEqual(Array.from(b));
  });

  it('changes when any bound-defining field changes', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });
    const baseBytes = canonicalCertificateBytes(cert);

    const mutated = { ...cert, minLatencyMs: 501 };
    const mutatedBytes = canonicalCertificateBytes(mutated);
    expect(Array.from(baseBytes)).not.toEqual(Array.from(mutatedBytes));

    const mutated2 = { ...cert, operationHash: 'different-op' };
    expect(Array.from(canonicalCertificateBytes(mutated2))).not.toEqual(Array.from(baseBytes));

    const mutated3 = { ...cert, certificateId: 'cert-2' };
    expect(Array.from(canonicalCertificateBytes(mutated3))).not.toEqual(Array.from(baseBytes));
  });
});

// ─── issueSlownessCertificate ───────────────────────────────────────

describe('issueSlownessCertificate', () => {
  it('produces a signed certificate that witnesses the claimed bound', async () => {
    const chain = await buildChainWithElapsed(750);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    expect(cert.source).toBe('GnosisSlownessCertificate');
    expect(cert.certificateId).toBe('cert-1');
    expect(cert.operationHash).toBe('op-hash');
    expect(cert.minLatencyMs).toBe(500);
    expect(cert.actualLatencyMs).toBe(750);
    expect(cert.issuerDid).toBe('did:key:issuer');
    expect(cert.issuedAtPLo).toBe(2000);
    expect(cert.issuerSignature.length).toBeGreaterThan(0);
  });

  it('refuses to issue when chain elapsed time is below the claimed bound', async () => {
    const chain = await buildChainWithElapsed(100); // only 100ms elapsed
    const issuer = mockSigner('did:key:issuer');

    await expect(
      issueSlownessCertificate({
        certificateId: 'cert-unsound',
        operationHash: 'op-hash',
        minLatencyMs: 500, // claiming 500ms
        attestationChain: chain,
        issuer,
        issuedAtPLo: 2000,
      })
    ).rejects.toThrow(/less than claimed/);
  });

  it('refuses to issue over a chain with fewer than 2 hops', async () => {
    const empty = initAttestationChain({
      chainId: 'c', originDid: 'd1', targetDid: 'd2',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 0,
    });
    const issuer = mockSigner('did:key:issuer');

    await expect(
      issueSlownessCertificate({
        certificateId: 'cert-empty',
        operationHash: 'op-hash',
        minLatencyMs: 0,
        attestationChain: empty,
        issuer,
        issuedAtPLo: 0,
      })
    ).rejects.toThrow(/at least 2 hops/);
  });

  it('refuses negative minLatencyMs', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    await expect(
      issueSlownessCertificate({
        certificateId: 'cert-neg',
        operationHash: 'op-hash',
        minLatencyMs: -1,
        attestationChain: chain,
        issuer,
        issuedAtPLo: 0,
      })
    ).rejects.toThrow(/non-negative/);
  });
});

// ─── verifySlownessCertificate ──────────────────────────────────────

describe('verifySlownessCertificate', () => {
  it('accepts a freshly issued valid certificate', async () => {
    const chain = await buildChainWithElapsed(750);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    const result = await verifySlownessCertificate(cert, ctx, mockVerifier);
    expect(result.valid).toBe(true);
    expect(result.chainValid).toBe(true);
    expect(result.minLatencyMet).toBe(true);
    expect(result.issuerSignatureValid).toBe(true);
    expect(result.actualLatencyConsistent).toBe(true);
    expect(result.reasons.length).toBe(0);
  });

  it('rejects cert where chain elapsed < minLatencyMs (even if issuer sig valid)', async () => {
    // Issue a cert normally, then mutate minLatencyMs upward to exceed
    // the chain's observed elapsed time. The issuer signature is now over
    // the old canonical bytes, so it ALSO fails -- both gates catch it.
    // To isolate the minLatencyMet gate, re-sign with the new body.
    const chain = await buildChainWithElapsed(300);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 300,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    // Forge a cert claiming a larger bound than the chain witnesses,
    // and sign it with the issuer's key (simulating a dishonest issuer).
    const overclaim = { ...cert, minLatencyMs: 9999 };
    const canonical = canonicalCertificateBytes(overclaim);
    const forgedSig = await issuer.sign(canonical);
    const forged = { ...overclaim, issuerSignature: forgedSig };

    const result = await verifySlownessCertificate(forged, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.minLatencyMet).toBe(false);
    // Issuer signature is self-consistent with the forged body, so it
    // passes -- but the temporal claim fails.
    expect(result.issuerSignatureValid).toBe(true);
    expect(result.reasons.some(r => /does not meet/.test(r))).toBe(true);
  });

  it('rejects cert with tampered issuer signature', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    const tampered = { ...cert, issuerSignature: new Uint8Array([1, 2, 3, 4]) };
    const result = await verifySlownessCertificate(tampered, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.issuerSignatureValid).toBe(false);
  });

  it('rejects cert whose body was silently modified post-signing', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    // Change operationHash without re-signing -- canonical bytes differ,
    // issuer signature no longer verifies.
    const mutated = { ...cert, operationHash: 'different-op' };
    const result = await verifySlownessCertificate(mutated, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.issuerSignatureValid).toBe(false);
  });

  it('rejects cert whose underlying attestation chain is broken', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    // Tamper the chain's first hop signature -- the chain's own
    // verification fails. Issuer sig still matches because chainId and
    // finalPayloadHash haven't moved; only the inner chain is broken.
    const brokenChain: PrismAttestationChain = {
      ...cert.attestationChain,
      hops: [
        { ...cert.attestationChain.hops[0], signature: new Uint8Array([9, 9, 9]) },
        cert.attestationChain.hops[1],
      ],
    };
    const brokenCert = { ...cert, attestationChain: brokenChain };

    const result = await verifySlownessCertificate(brokenCert, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.chainValid).toBe(false);
  });

  it('rejects cert whose actualLatencyMs field lies about the chain', async () => {
    const chain = await buildChainWithElapsed(500);
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueSlownessCertificate({
      certificateId: 'cert-1',
      operationHash: 'op-hash',
      minLatencyMs: 500,
      attestationChain: chain,
      issuer,
      issuedAtPLo: 2000,
    });

    // Re-sign a cert whose actualLatencyMs doesn't match the chain.
    const lying = { ...cert, actualLatencyMs: 99_999 };
    const canonical = canonicalCertificateBytes(lying);
    const sig = await issuer.sign(canonical);
    const lyingSigned = { ...lying, issuerSignature: sig };

    const result = await verifySlownessCertificate(lyingSigned, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.actualLatencyConsistent).toBe(false);
  });
});
